#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[501];
        scanf("%s", s);
        int n = strlen(s);
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'R') {
                count++;
            }
        }
        if (count % 2 == 0) {
            printf("Animesh\n");
        } else {
            printf("Malvika\n");
        }
    }
    return 0;
}

