code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = s.length();
            int count = 0;
            for (int i = 0; i < n; i++) {
                if (s.charAt(i) == 'R') {
                    count++;
                }
            }
            if (count % 2 == 0) {
                System.out.println("Animesh");
            } else {
                System.out.println("Malvika");
            }
        }
    }
}

